// Framer code file mirror: matches site fonts (Josefin Sans body, Iosevka Charon display).
import { addPropertyControls, ControlType } from "framer"
import { startTransition, useCallback, useEffect, useMemo, useState, type CSSProperties } from "react"

type CartItem = { id: string; name: string; price: number; quantity: number }

interface NewBeanCartDrawerProps {
    panelTitle: string
    checkoutLabel: string
    successMessage: string
    beanColor: string
    yellowColor: string
    surfaceColor: string
    cardColor: string
    textColor: string
    mutedColor: string
    headerFont: CSSProperties
    bodyFont: CSSProperties
    buttonFont: CSSProperties
    style?: CSSProperties
}

const starterItems: CartItem[] = [
    { id: "croissant", name: "Croissant", price: 3.25, quantity: 1 },
    { id: "latte", name: "Latte", price: 4, quantity: 1 },
]

const bagelItem: CartItem = { id: "bagel", name: "Bagel", price: 3.45, quantity: 1 }
const bagelImage =
    "https://images.unsplash.com/photo-1603046891744-76e6300f82ef?auto=format&fit=crop&w=700&q=80"
const taxRate = 0.115

/** Same families as canvas text: Menu / New Bean use Iosevka Charon; UI uses Josefin Sans. */
const FONT_BODY = "'Josefin Sans', sans-serif"
const FONT_DISPLAY = "'Iosevka Charon', sans-serif"
const SITE_FONTS_HREF =
    "https://fonts.googleapis.com/css2?family=Josefin+Sans:wght@400;500;600;700&family=Iosevka+Charon:wght@500;600;700&display=swap"

function useSiteFonts() {
    useEffect(() => {
        if (typeof document === "undefined") return
        const id = "new-bean-cart-fonts"
        if (document.getElementById(id)) return
        const link = document.createElement("link")
        link.id = id
        link.rel = "stylesheet"
        link.href = SITE_FONTS_HREF
        document.head.appendChild(link)
    }, [])
}

function withBodyFont(font: CSSProperties): CSSProperties {
    return { ...font, fontFamily: FONT_BODY }
}

function withDisplayFont(font: CSSProperties): CSSProperties {
    return { ...font, fontFamily: FONT_DISPLAY }
}

/**
 * New Bean Cart Drawer
 *
 * @framerIntrinsicWidth 1200
 * @framerIntrinsicHeight 800
 *
 * @framerSupportedLayoutWidth fixed
 * @framerSupportedLayoutHeight fixed
 */
export default function NewBeanCartDrawer(props: NewBeanCartDrawerProps) {
    const {
        panelTitle,
        checkoutLabel,
        successMessage,
        beanColor,
        yellowColor,
        surfaceColor,
        cardColor,
        textColor,
        mutedColor,
        headerFont,
        bodyFont,
        buttonFont,
    } = props

    useSiteFonts()

    const [isOpen, setIsOpen] = useState(false)
    const [showBagelPrompt, setShowBagelPrompt] = useState(false)
    const [items, setItems] = useState<CartItem[]>(starterItems)
    const [customerName, setCustomerName] = useState("")
    const [pickup, setPickup] = useState("ASAP")
    const [notice, setNotice] = useState("")

    const totals = useMemo(() => {
        const subtotal = items.reduce((sum, item) => sum + item.price * item.quantity, 0)
        const tax = subtotal * taxRate
        return { subtotal, tax, total: subtotal + tax }
    }, [items])

    const hasBagel = useMemo(() => items.some((item) => item.id === bagelItem.id), [items])
    const money = useCallback(
        (value: number) => new Intl.NumberFormat("en-US", { style: "currency", currency: "USD" }).format(value),
        []
    )
    const closePanel = useCallback(
        () => startTransition(() => {
            setIsOpen(false)
            setShowBagelPrompt(false)
        }),
        []
    )
    const openPanel = useCallback(() => startTransition(() => setIsOpen(true)), [])

    const updateQuantity = useCallback((id: string, delta: number) => {
        startTransition(() => {
            setItems((current) =>
                current
                    .map((item) => (item.id === id ? { ...item, quantity: item.quantity + delta } : item))
                    .filter((item) => item.quantity > 0)
            )
        })
    }, [])

    const resetCart = useCallback(() => startTransition(() => setItems(starterItems)), [])

    const addBagel = useCallback(() => {
        startTransition(() => {
            setItems((current) => (current.some((item) => item.id === bagelItem.id) ? current : [...current, bagelItem]))
            setShowBagelPrompt(false)
            setIsOpen(true)
        })
    }, [])

    const checkout = useCallback(() => {
        if (items.length === 0) {
            startTransition(() => setNotice("Your cart is empty."))
            return
        }

        if (!hasBagel) {
            startTransition(() => setShowBagelPrompt(true))
            return
        }

        const name = customerName.trim() || "friend"
        startTransition(() => {
            setNotice(successMessage.replace("{name}", name).replace("{pickup}", pickup))
            setItems([])
            setCustomerName("")
            setIsOpen(false)
        })
    }, [customerName, hasBagel, items.length, pickup, successMessage])

    useEffect(() => {
        if (typeof window === "undefined") return
        const onKeyDown = (event: KeyboardEvent) => {
            if (event.key === "Escape") {
                if (showBagelPrompt) startTransition(() => setShowBagelPrompt(false))
                else closePanel()
            }
        }
        window.addEventListener("keydown", onKeyDown)
        return () => window.removeEventListener("keydown", onKeyDown)
    }, [closePanel, showBagelPrompt])

    useEffect(() => {
        if (!notice || typeof window === "undefined") return
        const timeoutId = window.setTimeout(() => startTransition(() => setNotice("")), 3200)
        return () => window.clearTimeout(timeoutId)
    }, [notice])

    const buttonBase: CSSProperties = { border: "0", cursor: "pointer", ...withBodyFont(buttonFont) }

    return (
        <div
            style={{
                ...props.style,
                position: "relative",
                width: "100%",
                height: "100%",
                overflow: "visible",
                pointerEvents: "none",
                color: textColor,
                ...withBodyFont(bodyFont),
            }}
        >
            <button
                type="button"
                aria-label="Open cart"
                onClick={openPanel}
                style={{
                    pointerEvents: "auto",
                    position: "absolute",
                    top: 17,
                    left: "calc(50% + 58px)",
                    width: 142,
                    height: 42,
                    padding: 0,
                    opacity: 0,
                    background: "transparent",
                    border: "0",
                    cursor: "pointer",
                    zIndex: 30,
                }}
            />

            <div
                role="presentation"
                onClick={closePanel}
                style={{
                    pointerEvents: isOpen ? "auto" : "none",
                    position: "absolute",
                    inset: 0,
                    background: "rgba(39, 21, 29, 0.36)",
                    backdropFilter: "blur(4px)",
                    opacity: isOpen ? 1 : 0,
                    transition: "opacity 220ms ease",
                    zIndex: 8,
                }}
            />

            <aside
                role="dialog"
                aria-modal="true"
                aria-label={panelTitle}
                style={{
                    pointerEvents: isOpen ? "auto" : "none",
                    position: "absolute",
                    top: 0,
                    right: 0,
                    width: "min(440px, 100%)",
                    height: "100%",
                    padding: 24,
                    background: surfaceColor,
                    borderLeft: `3px solid ${beanColor}`,
                    boxShadow: "-18px 0 42px rgba(66, 27, 43, 0.22)",
                    transform: isOpen ? "translateX(0)" : "translateX(105%)",
                    transition: "transform 260ms ease",
                    zIndex: 9,
                    overflow: "auto",
                    ...withBodyFont(bodyFont),
                }}
            >
                <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 16 }}>
                    <h2 style={{ margin: 0, color: beanColor, ...withDisplayFont(headerFont) }}>{panelTitle}</h2>
                    <button
                        type="button"
                        aria-label="Close cart"
                        onClick={closePanel}
                        style={{
                            ...buttonBase,
                            width: 38,
                            height: 38,
                            color: "white",
                            background: beanColor,
                            borderRadius: "50%",
                            fontWeight: 800,
                        }}
                    >
                        x
                    </button>
                </div>

                <div style={{ display: "grid", gap: 12, margin: "24px 0" }}>
                    {items.length === 0 ? (
                        <div
                            style={{
                                padding: 24,
                                textAlign: "center",
                                color: mutedColor,
                                background: cardColor,
                                border: `2px dashed ${beanColor}66`,
                                borderRadius: 16,
                                ...withBodyFont(bodyFont),
                            }}
                        >
                            Your cart is empty.
                            <button
                                type="button"
                                onClick={resetCart}
                                style={{
                                    ...buttonBase,
                                    display: "block",
                                    margin: "14px auto 0",
                                    padding: "8px 16px",
                                    color: beanColor,
                                    background: yellowColor,
                                    borderRadius: 999,
                                }}
                            >
                                Restore sample order
                            </button>
                        </div>
                    ) : (
                        items.map((item) => (
                            <article
                                key={item.id}
                                style={{
                                    display: "grid",
                                    gridTemplateColumns: "1fr auto auto",
                                    alignItems: "center",
                                    gap: 12,
                                    padding: 14,
                                    background: cardColor,
                                    border: `2px solid ${beanColor}40`,
                                    borderRadius: 16,
                                }}
                            >
                                <div>
                                    <h3 style={{ margin: "0 0 3px", color: beanColor, ...withBodyFont(bodyFont), fontWeight: 600 }}>
                                        {item.name}
                                    </h3>
                                    <p style={{ margin: 0, color: mutedColor, ...withBodyFont(bodyFont), fontWeight: 400 }}>
                                        {money(item.price)} each
                                    </p>
                                </div>
                                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                                    <button
                                        type="button"
                                        aria-label={`Remove one ${item.name}`}
                                        onClick={() => updateQuantity(item.id, -1)}
                                        style={quantityButtonStyle(yellowColor, beanColor, buttonBase)}
                                    >
                                        -
                                    </button>
                                    <strong style={{ minWidth: 16, textAlign: "center", ...withBodyFont(bodyFont), fontWeight: 600 }}>
                                        {item.quantity}
                                    </strong>
                                    <button
                                        type="button"
                                        aria-label={`Add one ${item.name}`}
                                        onClick={() => updateQuantity(item.id, 1)}
                                        style={quantityButtonStyle(yellowColor, beanColor, buttonBase)}
                                    >
                                        +
                                    </button>
                                </div>
                                <strong style={{ color: beanColor, ...withBodyFont(bodyFont), fontWeight: 600 }}>
                                    {money(item.price * item.quantity)}
                                </strong>
                            </article>
                        ))
                    )}
                </div>

                <div
                    style={{
                        display: "grid",
                        gap: 9,
                        paddingTop: 17,
                        borderTop: `3px solid ${beanColor}`,
                        ...withBodyFont(bodyFont),
                    }}
                >
                    <SummaryRow label="Subtotal" value={money(totals.subtotal)} font={bodyFont} />
                    <SummaryRow label="Tax" value={money(totals.tax)} font={bodyFont} />
                    <SummaryRow label="Total Payable" value={money(totals.total)} large color={beanColor} font={bodyFont} />
                </div>

                <div style={{ display: "grid", gap: 12, marginTop: 24 }}>
                    <h3 style={{ margin: 0, color: beanColor, ...withBodyFont(bodyFont), fontWeight: 700 }}>Checkout</h3>
                    <label style={{ display: "grid", gap: 5, color: beanColor, ...withBodyFont(bodyFont), fontWeight: 600 }}>
                        Name
                        <input
                            value={customerName}
                            onChange={(event) => startTransition(() => setCustomerName(event.target.value))}
                            placeholder="Your name"
                            style={inputStyle(beanColor, bodyFont)}
                        />
                    </label>
                    <label style={{ display: "grid", gap: 5, color: beanColor, ...withBodyFont(bodyFont), fontWeight: 600 }}>
                        Pickup time
                        <select
                            value={pickup}
                            onChange={(event) => startTransition(() => setPickup(event.target.value))}
                            style={inputStyle(beanColor, bodyFont)}
                        >
                            <option>ASAP</option>
                            <option>15 minutes</option>
                            <option>30 minutes</option>
                        </select>
                    </label>
                    <button
                        type="button"
                        onClick={checkout}
                        style={{
                            ...buttonBase,
                            minHeight: 45,
                            color: beanColor,
                            background: yellowColor,
                            border: `2px solid ${yellowColor}`,
                            borderRadius: 999,
                            opacity: items.length === 0 ? 0.68 : 1,
                            fontWeight: 700,
                        }}
                    >
                        {checkoutLabel}
                    </button>
                </div>
            </aside>

            {showBagelPrompt && (
                <div style={{ pointerEvents: "auto", position: "absolute", inset: 0, zIndex: 20 }}>
                    <div
                        onClick={() => startTransition(() => setShowBagelPrompt(false))}
                        style={{ position: "absolute", inset: 0, background: "rgba(255, 255, 255, 0.48)", backdropFilter: "blur(8px)" }}
                    />
                    <section
                        role="dialog"
                        aria-modal="true"
                        aria-label="Bagel incentive"
                        style={{
                            position: "absolute",
                            top: "50%",
                            left: "50%",
                            transform: "translate(-50%, -50%)",
                            display: "grid",
                            gridTemplateColumns: "220px 1fr",
                            gap: 24,
                            width: "min(690px, calc(100% - 36px))",
                            padding: 24,
                            background: surfaceColor,
                            border: `4px solid ${beanColor}`,
                            borderRadius: 22,
                            boxShadow: "0 22px 60px rgba(66, 27, 43, 0.22)",
                            ...withBodyFont(bodyFont),
                        }}
                    >
                        <article
                            style={{
                                position: "relative",
                                padding: 16,
                                background: cardColor,
                                border: `3px solid ${beanColor}`,
                                borderRadius: 18,
                            }}
                        >
                            <span
                                style={{
                                    position: "absolute",
                                    top: -14,
                                    right: 16,
                                    padding: "4px 10px",
                                    color: "white",
                                    background: "#ff1010",
                                    borderRadius: 5,
                                    fontSize: 13,
                                    fontWeight: 800,
                                    ...withBodyFont(buttonFont),
                                }}
                            >
                                ONLY 1 LEFT
                            </span>
                            <img src={bagelImage} alt="Bagel" style={{ width: "100%", aspectRatio: "1 / 1", objectFit: "cover", borderRadius: 14, display: "block" }} />
                            <div style={{ display: "flex", justifyContent: "space-between", gap: 10, margin: "12px 0", color: beanColor, ...withBodyFont(bodyFont), fontWeight: 600 }}>
                                <strong>Bagel</strong>
                                <strong>{money(bagelItem.price)}</strong>
                            </div>
                            <button
                                type="button"
                                onClick={addBagel}
                                style={{
                                    ...buttonBase,
                                    width: "100%",
                                    minHeight: 38,
                                    color: yellowColor,
                                    background: beanColor,
                                    borderRadius: 999,
                                    fontWeight: 800,
                                }}
                            >
                                Add to Cart
                            </button>
                        </article>
                        <div style={{ color: beanColor }}>
                            <h2 style={{ margin: "0 0 18px", ...withDisplayFont(headerFont), fontSize: 30 }}>How does it help?</h2>
                            <ul
                                style={{
                                    margin: "0 0 18px",
                                    paddingLeft: 22,
                                    color: "#6e300a",
                                    ...withBodyFont(bodyFont),
                                    fontSize: 20,
                                    fontWeight: 600,
                                }}
                            >
                                <li>Reduces food wastage</li>
                                <li>Preparation of new food</li>
                            </ul>
                            <p style={{ margin: "0 0 22px", color: textColor, ...withBodyFont(bodyFont), fontWeight: 400 }}>
                                <strong>This is just an incentive.</strong>
                                <br />
                                This should NOT be a forced buy. No problem if you deny!
                            </p>
                            <button
                                type="button"
                                onClick={() => startTransition(() => setShowBagelPrompt(false))}
                                style={{
                                    ...buttonBase,
                                    float: "right",
                                    padding: "9px 16px",
                                    color: "#ff1010",
                                    background: surfaceColor,
                                    border: "2px solid #ff1010",
                                    borderRadius: 10,
                                    fontWeight: 600,
                                }}
                            >
                                No, thanks!
                            </button>
                        </div>
                    </section>
                </div>
            )}

            {notice && (
                <div
                    role="status"
                    aria-live="polite"
                    style={{
                        pointerEvents: "none",
                        position: "absolute",
                        left: "50%",
                        bottom: 24,
                        transform: "translateX(-50%)",
                        maxWidth: "calc(100% - 32px)",
                        padding: "12px 18px",
                        color: "white",
                        background: "#1f7a48",
                        borderRadius: 999,
                        boxShadow: "0 18px 42px rgba(66, 27, 43, 0.22)",
                        zIndex: 25,
                        ...withBodyFont(bodyFont),
                    }}
                >
                    {notice}
                </div>
            )}
        </div>
    )
}

function SummaryRow(props: { label: string; value: string; large?: boolean; color?: string; font: CSSProperties }) {
    const { label, value, large, color, font } = props
    return (
        <div
            style={{
                ...withBodyFont(font),
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                fontSize: large ? 22 : font.fontSize,
                fontWeight: large ? 700 : font.fontWeight,
                color,
            }}
        >
            <span>{label}</span>
            <strong>{value}</strong>
        </div>
    )
}

function quantityButtonStyle(yellowColor: string, beanColor: string, base: CSSProperties): CSSProperties {
    return { ...base, width: 30, height: 30, color: beanColor, background: yellowColor, borderRadius: "50%", fontWeight: 800 }
}

function inputStyle(beanColor: string, font: CSSProperties): CSSProperties {
    return {
        width: "100%",
        padding: "10px 12px",
        color: "#27151d",
        background: "white",
        border: `2px solid ${beanColor}66`,
        borderRadius: 12,
        outline: "none",
        ...withBodyFont(font),
        fontWeight: 400,
    }
}

addPropertyControls(NewBeanCartDrawer, {
    panelTitle: { type: ControlType.String, title: "Panel Title", defaultValue: "Cart" },
    checkoutLabel: { type: ControlType.String, title: "Checkout Label", defaultValue: "Checkout" },
    successMessage: {
        type: ControlType.String,
        title: "Success Message",
        defaultValue: "Thanks, {name}! Your order will be ready in {pickup}.",
        displayTextArea: true,
    },
    beanColor: { type: ControlType.Color, title: "Bean Color", defaultValue: "#421B2B" },
    yellowColor: { type: ControlType.Color, title: "Yellow", defaultValue: "#FFBF00" },
    surfaceColor: { type: ControlType.Color, title: "Panel Surface", defaultValue: "#FFFFFF" },
    cardColor: { type: ControlType.Color, title: "Card Surface", defaultValue: "#FFF4D8" },
    textColor: { type: ControlType.Color, title: "Text", defaultValue: "#27151D" },
    mutedColor: { type: ControlType.Color, title: "Muted Text", defaultValue: "#725C63" },
    headerFont: {
        type: ControlType.Font,
        title: "Display (Iosevka)",
        controls: "extended",
        defaultFontType: "sans-serif",
        defaultValue: { fontSize: 42, variant: "Bold", letterSpacing: "-0.04em", lineHeight: "1em" },
    },
    bodyFont: {
        type: ControlType.Font,
        title: "Body (Josefin)",
        controls: "extended",
        defaultFontType: "sans-serif",
        defaultValue: { fontSize: 16, variant: "Medium", letterSpacing: "-0.01em", lineHeight: "1.2em" },
    },
    buttonFont: {
        type: ControlType.Font,
        title: "Button (Josefin)",
        controls: "extended",
        defaultFontType: "sans-serif",
        defaultValue: { fontSize: 14, variant: "Bold", letterSpacing: "-0.01em", lineHeight: "1em" },
    },
})
